  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary, OnboardingState, SuggestionSummary } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  readEntityName,
  9→  searchEntitiesByEmbedding,
 10→  type ConversationEntity,
 11→  type RankedEntity,
 12→  type WorkspaceDecisionSummary,
 13→  type WorkspaceProjectSummary,
 14→  type WorkspaceQuestionSummary,
 15→} from "../graph/queries";
 16→import { listWorkspaceOpenObservations } from "../observation/queries";
 17→import { listWorkspacePendingSuggestions } from "../suggestion/queries";
 18→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 19→import type { GraphEntityRecord } from "../extraction/types";
 20→
 21→export type DiscussedEntityContext = {
 22→  kind: string;
 23→  name: string;
 24→  status?: string;
 25→};
 26→
 27→export type ChatContext = {
 28→  conversationEntities: ConversationEntity[];
 29→  relevantEntities?: RankedEntity[];
 30→  workspaceDescription?: string;
 31→  workspaceSummary: {
 32→    projects: WorkspaceProjectSummary[];
 33→    recentDecisions: WorkspaceDecisionSummary[];
 34→    openQuestions: WorkspaceQuestionSummary[];
 35→    openObservations: ObservationSummary[];
 36→    pendingSuggestions: SuggestionSummary[];
 37→  };
 38→  onboardingSummary?: string;
 39→  discussedEntity?: DiscussedEntityContext;
 40→};
 41→
 42→type ChatContextLoaders = {
 43→  listConversationEntities: typeof listConversationEntities;
 44→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 45→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 46→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 47→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 48→  listWorkspacePendingSuggestions: typeof listWorkspacePendingSuggestions;
 49→  loadOnboardingSummary: typeof loadOnboardingSummary;
 50→};
 51→
 52→export async function buildChatContext(input: {
 53→  surreal: Surreal;
 54→  conversationRecord: RecordId<"conversation", string>;
 55→  workspaceRecord: RecordId<"workspace", string>;
 56→  workspaceDescription?: string;
 57→  loaders?: ChatContextLoaders;
 58→  inheritedEntityIds?: RecordId[];
 59→  discussesRecord?: RecordId;
 60→  userMessageEmbedding?: number[];
 61→}): Promise<ChatContext> {
 62→  const loaders = input.loaders ?? {
 63→    listConversationEntities,
 64→    listWorkspaceProjectSummaries,
 65→    listWorkspaceRecentDecisions,
 66→    listWorkspaceOpenQuestions,
 67→    listWorkspaceOpenObservations,
 68→    listWorkspacePendingSuggestions,
 69→    loadOnboardingSummary,
 70→  };
 71→
 72→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, pendingSuggestions, onboardingSummary] = await Promise.all([
 73→    loaders.listConversationEntities({
 74→      surreal: input.surreal,
 75→      conversationRecord: input.conversationRecord,
 76→      workspaceRecord: input.workspaceRecord,
 77→      limit: 60,
 78→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 79→        ? { inheritedEntityIds: input.inheritedEntityIds }
 80→        : {}),
 81→    }),
 82→    loaders.listWorkspaceProjectSummaries({
 83→      surreal: input.surreal,
 84→      workspaceRecord: input.workspaceRecord,
 85→      limit: 20,
 86→    }),
 87→    loaders.listWorkspaceRecentDecisions({
 88→      surreal: input.surreal,
 89→      workspaceRecord: input.workspaceRecord,
 90→      limit: 12,
 91→    }),
 92→    loaders.listWorkspaceOpenQuestions({
 93→      surreal: input.surreal,
 94→      workspaceRecord: input.workspaceRecord,
 95→      limit: 12,
 96→    }),
 97→    loaders.listWorkspaceOpenObservations({
 98→      surreal: input.surreal,
 99→      workspaceRecord: input.workspaceRecord,
100→      limit: 10,
101→    }),
102→    loaders.listWorkspacePendingSuggestions({
103→      surreal: input.surreal,
104→      workspaceRecord: input.workspaceRecord,
105→      limit: 10,
106→    }),
107→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
108→  ]);
109→
110→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
111→  let relevantEntities: RankedEntity[] | undefined;
112→  if (input.userMessageEmbedding) {
113→    const queryEmbedding = input.userMessageEmbedding;
114→    const conversationEntityIds = new Set(
115→      conversationEntities.map((e) => e.id),
116→    );
117→    const ranked = await searchEntitiesByEmbedding({
118→      surreal: input.surreal,
119→      workspaceRecord: input.workspaceRecord,
120→      queryEmbedding,
121→      limit: 15,
122→    });
123→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
124→    if (filtered.length > 0) {
125→      relevantEntities = filtered.slice(0, 10);
126→    }
127→  }
128→
129→  let discussedEntity: DiscussedEntityContext | undefined;
130→  if (input.discussesRecord) {
131→    const entityRecord = input.discussesRecord as GraphEntityRecord;
132→    const name = await readEntityName(input.surreal, entityRecord);
