 89→          kind: "project" as const,
 90→          title: input.title,
 91→        };
 92→      }
 93→
 94→      if (input.kind === "task") {
 95→        const taskRecord = new RecordId("task", entityId);
 96→        await deps.surreal.create(taskRecord).content({
 97→          title: input.title,
 98→          status: "open",
 99→          workspace: context.workspaceRecord,
100→          ...(input.category ? { category: input.category } : {}),
101→          ...(input.priority ? { priority: input.priority } : {}),
102→          ...(embedding ? { embedding } : {}),
103→          created_at: now,
104→          updated_at: now,
105→        });
106→
107→        if (input.project) {
108→          try {
109→            const projectRecord = await resolveWorkspaceProjectRecord({
110→              surreal: deps.surreal,
111→              workspaceRecord: context.workspaceRecord,
112→              projectInput: input.project,
113→            });
114→            await deps.surreal
115→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
116→                added_at: now,
117→              })
118→              .output("after");
119→          } catch {
120→            // project resolution is best-effort
121→          }
122→        }
123→
124→        void seedDescriptionEntry({
125→          surreal: deps.surreal,
126→          targetRecord: taskRecord,
127→          text: input.rationale,
128→        }).catch(() => undefined);
129→
130→        await createExtractionProvenanceEdge({
131→          surreal: deps.surreal,
132→          sourceRecord: context.currentMessageRecord,
133→          targetRecord: taskRecord,
134→          now,
135→          confidence: 0.95,
136→          model: deps.extractionModelId,
137→          fromText: input.title,
