151→      await deps.surreal.create(featureRecord).content({
152→        name: input.title,
153→        status: "active",
154→        ...(input.category ? { category: input.category } : {}),
155→        ...(embedding ? { embedding } : {}),
156→        created_at: now,
157→        updated_at: now,
158→      });
159→
160→      if (input.project) {
161→        try {
162→          const projectRecord = await resolveWorkspaceProjectRecord({
163→            surreal: deps.surreal,
