      [
        "SELECT id, text, status, priority, category, created_at",
        "FROM question",
        "WHERE status = 'open'",
        "AND priority IN ['high', 'critical']",
        `AND ${buildWorkspaceScopeClause("question")}`,
        "ORDER BY created_at DESC",
